import { flattenObj, capitalizeFirstLetter } from "../../shared/util";
import type { FacetDetails } from "../types/facet";
import type { QueryDetails } from "../types/query";
import type { MatrixConfigJSON } from "shared/types/configJSON";

function remove(obj: Record<string, unknown>, key: string): void {
  for (const k in obj) {
    if (k === key) {
      delete obj[k];
    } else if (typeof obj[k] === "object" && obj[k] !== null) {
      remove(obj[k] as Record<string, unknown>, key);
    }
  }
}

function removeObjectArray(obj: Record<string, any>, key: string, value: string | undefined): void {
  const currentFacet = obj.facets?.[key];

  if (!Array.isArray(currentFacet) || currentFacet.length === 0) {
    return;
  }

  const updatedFacet = currentFacet.filter((item: unknown) => item !== value);

  if (updatedFacet.length > 0) {
    obj.facets[key] = updatedFacet;
  } else {
    delete obj.facets[key];
  }
}

export function hyperLink(
  query: QueryDetails,
  facet: FacetDetails | null,
  pageNumber?: number,
  numberRank?: number,
  facetValueInArray?: string,
  config?: MatrixConfigJSON,
) {
  const newStartRank =
    pageNumber && numberRank && 1 + (pageNumber - 1) * numberRank;
  const newQuery = JSON.parse(JSON.stringify(query)); //deep clone

  if (facet && facet.meta && (facet.type === "tag" || facet.type === "multiCheckbox") ) {
    if(facet.type === "tag"){
      remove(newQuery, facet.meta);
    }
    if(facet.type === "multiCheckbox"){
      removeObjectArray(newQuery, facet.meta, facetValueInArray);
    }

  }
  const flattenQuery = flattenObj(newQuery);
  
  return (
    "?" +
    Object.entries(flattenQuery)
      .filter((key) => {
        const param = Object.values(key);

        if (param[1] === "") {
          return false;
        } else {
          switch (param[0]) {
            case "interacted":
              return false;
            case "num_rank":
              return false;
            case "start_rank":
              return false;
            default:
              return true;
          }
        }
      })
      .map((entry) => {
        const [rawKey, value] = entry;

        // ✅ detect array keys like level[0], level[1]
        const isArrayKey = /\[\d+\]/.test(rawKey);

        // remove [0], [1], etc.
        const normalizedKey = rawKey.replace(/\[\d+\]/g, "");

        // special cases first
        if (/fixedParameters/.test(rawKey)) {
          return (
            encodeURIComponent(rawKey.substring(16)) +
            "=" +
            encodeURIComponent(value)
          );
        }

        if (/fixedFacets/.test(rawKey)) {
          return (
            encodeURIComponent(`meta_${rawKey.substring(12)}_sand`) +
            "=" +
            encodeURIComponent(value)
          );
        }

        if (/parameters/.test(rawKey)) {
          return (
            encodeURIComponent(rawKey.substring(11)) +
            "=" +
            encodeURIComponent(value)
          );
        }

        // ✅ NEW: special handling for array-based keys
        if (isArrayKey) {
          const findFacet = config?.facetLabels?.find( facetLabel => facetLabel.meta === normalizedKey);
          const facetName = findFacet?.facetName ? findFacet.facetName : capitalizeFirstLetter(normalizedKey);
          return (
            encodeURIComponent(`f±${facetName}|${normalizedKey}[]`) +
            "=" +
            encodeURIComponent(value)
          );
        }

        // existing switch
        switch (normalizedKey) {
          case "collection":
          case "profile":
          case "query":
            return (
              encodeURIComponent(normalizedKey) +
              "=" +
              encodeURIComponent(value)
            );

          case "sortType":
            return (
              encodeURIComponent("sort") +
              "=" +
              encodeURIComponent(value)
            );

          case "startRank":
            return (
              encodeURIComponent("start_rank") +
              "=" +
              encodeURIComponent(facet ? value : newStartRank || "")
            );

          case "numRanks":
            return (
              encodeURIComponent("num_rank") +
              "=" +
              encodeURIComponent(value)
            );

          default:
            return (
              encodeURIComponent(`meta_${normalizedKey}_sand`) +
              "=" +
              encodeURIComponent(value)
            );
        }
      })
      .join("&")
  );
}
