import React, { useState, useEffect, useRef } from "react";
import PropTypes from "prop-types";
import { suggest } from "../../logic/funnelback";
import Clear from "./finder__clear";
import useHasMounted from "../../logic/has-mounted"; // ✅ added
import { isRequestCanceled } from "../../util";
import type { QueryInput } from "../../types/query/query";

const maximumSuggestions = 5;
const escapeKey = "Escape",
  endKey = "End",
  homeKey = "Home",
  arrowUp = "ArrowUp",
  arrowDown = "ArrowDown";

function highlightQueryTerm(suggestion: string, partialQuery: string) {
  return (
    <span>
      <span className="sr-only">{suggestion}</span>
      <span aria-hidden="true">
        <span className="v26-finder__suggestion">
          {suggestion.slice(
            suggestion.indexOf(partialQuery.toLowerCase()),
            suggestion.indexOf(partialQuery.toLowerCase()) +
              partialQuery.length,
          )}
        </span>
        {suggestion.slice(
          suggestion.indexOf(partialQuery.toLowerCase()) + partialQuery.length,
        )}
      </span>
    </span>
  );
}

function Finder__Query(props: QueryInput) {
  const searchIconClassName =
    props.config.site && props.config.site === "bayes"
      ? "fa fa-search fa-lg"
      : "fal fa-sharp fa-search";

  const searchButtonLabel = props.config.site && props.config.site === "city"
    ? "Search"
    : "Find";

  const hasMounted = useHasMounted(); // ✅ detect client vs server

  const inputRef = useRef<HTMLInputElement>(null);
  const [partialQuery, setPartialQuery] = useState(props.query.query || "");
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [call, setCall] = useState<AbortController | null>(null);
  const [inputId] = useState("v26-finder--" + props.query.collection);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [activeSuggestionID, setActiveSuggestionID] = useState("");

  useEffect(() => {
    setPartialQuery(props.query.query);
  }, [props.query.query, props.updating]);

  useEffect(() => {
    return () => {
      if (call) call.abort();
    };
  }, [call]);

  function focusInput() {
    if (inputRef.current) {
      inputRef.current.focus();
    }
  }

  const clearQuery = () => {
    if (call) call.abort();

    setPartialQuery("");
    setSuggestions([]);
    focusInput();

    const newQuery = { ...props.query };
    newQuery.misspelling = null;
    newQuery.query = "";
    newQuery.sortType = props.config.sort[0].type;
    newQuery.startRank = 1;
    newQuery.interacted = true;

    props.update.query(newQuery);
    props.update.results(!props.update.updateState);
  };

  const submitForm = (query?: string) => {
    if (!query) return;

    if (call) call.abort();
    setSuggestions([]);

    const newQuery = props.query;

    newQuery.misspelling = null;
    newQuery.query = query ? query : partialQuery ? partialQuery : "";
    newQuery.sortType = partialQuery ? "" : props.config.sort[0].type;
    newQuery.startRank = 1;
    newQuery.interacted = true;

    props.update.query(newQuery);
    props.update.results(!props.update.updateState);
  };

  const clear = partialQuery && (
    <Clear
      clear={() => {
        const value = inputRef.current ? inputRef.current.value : "";

        if(inputRef.current)  inputRef.current.value = "";
        setPartialQuery("");
        setShowSuggestions(false);
        setActiveSuggestionID("");
        setSuggestions([]);

        if(value === props.query.query){
          clearQuery();
        }
        
      }}
      site={props.config.site || "city"}
    />
  );

  const submitSuggestion = (suggestion: string) => {
    setShowSuggestions(false);
    setSuggestions([]);
    focusInput();
    submitForm(suggestion);
  };
  const suggestionsList = suggestions && suggestions.length > 0 && (
    <ul
      role="listbox"
      aria-label="Search suggestions"
      aria-activedescendant={activeSuggestionID}
      className={
        showSuggestions
          ? "v26-finder__query__suggestions show"
          : "v26-finder__query__suggestions hide"
      }
    >
      {[...new Set(suggestions)]
        .slice(0, maximumSuggestions)
        .map((suggestion, i) => (
          <li key={suggestion} role="option" id={inputId + "--" + i}>
            <button
              type="button"
              onBlur={() => {
                setActiveSuggestionID("");
                setShowSuggestions(false);
              }}
              onFocus={() => setShowSuggestions(true)}
              onMouseDown={() => submitSuggestion(suggestion)}
              onClick={() => submitSuggestion(suggestion)}
              onKeyDown={(e) => {
                const target = e.target as HTMLElement;
                
                switch (e.key) {
                  case escapeKey:
                    e.currentTarget
                      .closest(".v26-finder__query")
                      ?.querySelector("input")
                      ?.focus();
                    setSuggestions([]);
                    setActiveSuggestionID("");
                    break;
                  case arrowUp:
                    if (
                          target.parentElement?.previousElementSibling &&
                          target.parentElement.previousElementSibling.querySelector("button")
                        ) {
                          e.preventDefault();

                          target.parentElement.previousElementSibling
                            .querySelector("button")
                            ?.focus();

                          setActiveSuggestionID(
                            target.parentElement.previousElementSibling.id
                          );
                        } else {
                          e.preventDefault();

                          target.parentElement?.parentElement?.parentElement
                            ?.querySelector("input")
                            ?.focus();

                          setActiveSuggestionID("");
                        }
                      break;
                  case arrowDown:
                    e.preventDefault();
                    e.currentTarget.parentElement?.nextElementSibling
                      ?.querySelector("button")
                      ?.focus();
                    break;
                  case homeKey: {
                    e.preventDefault();
                    const first = e.currentTarget.closest("ul")?.firstChild;
                    if (first instanceof Element) {
                      first.querySelector("button")?.focus();
                    }
                    break;
                  }
                  case endKey: {
                    e.preventDefault();
                    const last = e.currentTarget.closest("ul")?.lastChild;
                    if (last instanceof Element) {
                      last.querySelector("button")?.focus();
                    }
                    break;
                  }
                }
              }}
            >
              {highlightQueryTerm(suggestion, partialQuery)}
            </button>
          </li>
        ))}
    </ul>
  );


  //shared props between input
  const inputSharedProps = {
    id: inputId,
    name: "query",
    placeholder: props.config.placeholder,
    type: "text",
    className: "v26-finder__query-input",
  };

  //Input for server side render
  const fallbackInput = (
    <input
      {...inputSharedProps}
      defaultValue={partialQuery}
      autoComplete="off"
    />
  );

  //Input for client side render
  const searchInput = (
    <input
    {...inputSharedProps}
      ref={inputRef}
        value={partialQuery}
        onKeyDown={(e) => {
          if (e.key === escapeKey) clearQuery();
          else if (e.key === arrowDown && suggestions.length > 0) {
            e.preventDefault();
            const button = e.currentTarget.parentElement?.querySelector(
              ".v26-finder__query__suggestions button",
            ) as HTMLButtonElement | null;
            button?.focus();
            setActiveSuggestionID(
              e.currentTarget.parentElement?.querySelector(
                ".v26-finder__query__suggestions li",
              )?.id || "",
            );
          }
        }}
        onFocus={() => setShowSuggestions(true)}
        onBlur={() => setShowSuggestions(false)}
        onChange={(e) => {
          const val = e.target.value;
          setPartialQuery(val);
          setSuggestions([]);
          if (call) call.abort();

          if (val) {
            const [promise, newCall] = suggest(
              props.query.collection,
              val,
              props.config.site ? props.config.site : undefined,
            );
            setCall(newCall);
            promise
              .then((data) => setSuggestions(data))
              .catch((error) => {
                if (!isRequestCanceled(error)) {
                  setSuggestions([]);
                }
              });
          } else {
            setSuggestions([]);
          }
        }}
    />
  );

  // ✅ Server-side fallback
  if (!hasMounted) {
    return props.config.site === "city" ? (
      <fieldset className="v26-finder__fullwidth__wrapper ">
          <div className="v26-finder__fullwidth__inner">
            <div className="v26-finder__query">
              <label className="sr-only" htmlFor={inputId}>
                {`Search ${props.config.summariseAs && props.config.summariseAs.plural}`}
              </label>
              <div className="v26-finder__query__input__wrapper">
                {fallbackInput}
                {clear}
                <button
                  type="submit"
                  className="v26-finder__query__submit"
                  onClick={() => submitForm(inputRef.current ? inputRef.current.value : "")}
                >
                  <span
                    className={`${searchIconClassName} v26-finder__query__submit__icon`}
                    aria-hidden="true"
                  />
                  <span className="v26-finder__query__submit__text">{searchButtonLabel}</span>
                </button>
              </div>
            </div>
          </div>
        </fieldset>
    ) :
    (
      <fieldset className="v26-finder__query">
        <div>
          <div className="v26-finder__query__input">
            <label className="sr-only" htmlFor={inputId}>
              {`Search ${props.config.summariseAs && props.config.summariseAs.plural}`}
            </label>
            {fallbackInput}
          </div>
          <button type="submit" className="v26-finder__query__submit">
            <span
              className="fal fa-sharp fa-search finder__query__submit__icon"
              aria-hidden="true"
            />
            <span className="v26-finder__query__submit__text">{searchButtonLabel}</span>
          </button>
        </div>
      </fieldset>
    );
  }

  // ✅ Interactive version after hydration
  return props.config.site === "city" ? (
    <fieldset className="v26-finder__fullwidth__wrapper ">
        <div className="v26-finder__fullwidth__inner">
          <div className="v26-finder__query">
          <label className="sr-only" htmlFor={inputId}>
            {`Search ${props.config.summariseAs && props.config.summariseAs.plural}`}
          </label>
          <div className="v26-finder__query__input__wrapper">
            {searchInput}
            {clear}
            <button
              type="submit"
              className="v26-finder__query__submit"
              onClick={() => submitForm(inputRef.current ? inputRef.current.value : "")}
            >
              <span
                className={`${searchIconClassName} v26-finder__query__submit__icon`}
                aria-hidden="true"
              />
              <span className="v26-finder__query__submit__text">{searchButtonLabel}</span>
            </button>
          {suggestionsList}
          </div>
        </div>
      </div>
    </fieldset>
  ) : (
    <fieldset className="v26-finder__query">
      <div>
        <div className="v26-finder__query__input">
          <div className="v26-finder__query__icon--wrapper">
            <span
              className={`finder__icon ${searchIconClassName} icon`}
              aria-hidden="true"
            ></span>
          </div>
          <label className="sr-only" htmlFor={inputId}>
            {`Search ${props.config.summariseAs && props.config.summariseAs.plural}`}
          </label>
          {searchInput}
          {suggestionsList}
          {clear}
        </div>
        <button
          type="submit"
          className="v26-finder__query__submit"
          onClick={() => submitForm(inputRef.current ? inputRef.current.value : "")}
        >
          <span
            className={`${searchIconClassName} v26-finder__query__submit__icon`}
            aria-hidden="true"
          />
          <span className="v26-finder__query__submit__text">{searchButtonLabel}</span>
        </button>
      </div>
    </fieldset>
  );
}

Finder__Query.propTypes = {
  config: PropTypes.object,
  query: PropTypes.object,
  update: PropTypes.object,
  updating: PropTypes.bool,
};

export default Finder__Query;
